import torch
from torch import nn
from torch.nn.parameter import UninitializedParameter

try:
    nn.Bilinear(0, 3, 4)
except ValueError as e:
    print("regular-error", e)
else:
    raise SystemExit("Bilinear(0, ...) unexpectedly succeeded")

class LazyBilinear(nn.modules.lazy.LazyModuleMixin, nn.Bilinear):
    cls_to_become = nn.Bilinear
    weight: UninitializedParameter
    bias: UninitializedParameter

    def __init__(self, out_features, bias=True, device=None, dtype=None):
        factory_kwargs = {"device": device, "dtype": dtype}
        nn.Bilinear.__init__(self, 0, 0, out_features, False)
        self.weight = UninitializedParameter(**factory_kwargs)
        self.out_features = out_features
        if bias:
            self.bias = UninitializedParameter(**factory_kwargs)

    def reset_parameters(self):
        if not self.has_uninitialized_params() and self.in1_features != 0:
            super().reset_parameters()

    def initialize_parameters(self, input1, input2):
        if self.has_uninitialized_params():
            with torch.no_grad():
                self.in1_features = input1.shape[-1]
                self.in2_features = input2.shape[-1]
                self.weight.materialize((self.out_features, self.in1_features, self.in2_features))
                if self.bias is not None:
                    self.bias.materialize((self.out_features,))
                self.reset_parameters()

m = LazyBilinear(5)
out = m(torch.randn(2, 3), torch.randn(2, 4))
print("lazy-output-shape", tuple(out.shape), type(m).__name__, m.in1_features, m.in2_features)
